Here are the public test cases for feature01_point:
{
  "description": "A point is the simplest geometry: a single coordinate. Serializing a point produces a JSON object carrying a type discriminator and a coordinate array given in axis order (horizontal first, then vertical, then an optional elevation as a third element). Every supplied coordinate component is always emitted, including components whose value is zero. Deserializing the same shape reconstructs an equal point, preserving the optional elevation only when it was present. Two points built from the same coordinate compare equal and produce the same hash code; differing coordinates compare unequal.",
  "cases": [
    {
      "input": {
        "op": "serialize",
        "object": {
          "type": "Point",
          "coordinates": [
            90.65464646,
            53.2455662
          ]
        },
        "formatting": "none"
      },
      "expected_output": "{\"type\":\"Point\",\"coordinates\":[90.65464646,53.2455662]}\n"
    },
    {
      "input": {
        "op": "serialize",
        "object": {
          "type": "Point",
          "coordinates": [
            90.65464646,
            53.2455662,
            200.4567
          ]
        },
        "formatting": "none"
      },
      "expected_output": "{\"type\":\"Point\",\"coordinates\":[90.65464646,53.2455662,200.4567]}\n"
    },
    {
      "input": {
        "op": "equals",
        "kind": "geometry",
        "left": {
          "type": "Point",
          "coordinates": [
            90.65464646,
            53.2455662
          ]
        },
        "right": {
          "type": "Point",
          "coordinates": [
            90.65464646,
            53.2455662
          ]
        }
      },
      "expected_output": "equals=true\nequals_reverse=true\nop_equals=true\nop_not_equals=false\nhash_equal=true\n"
    }
  ]
}

Here are the public test cases for feature02_linestring:
{
  "description": "A line string is an ordered sequence of two or more coordinates. It serializes to a type discriminator plus an array of coordinate arrays, and round-trips back to an equal value. A line string can report whether it is closed (its first and last coordinates coincide) and whether it forms a linear ring (closed and having at least four coordinates). Construction validates its input: a null coordinate sequence is rejected as a missing required argument, and a sequence with fewer than two coordinates is rejected as out of range. Equal coordinate sequences yield equal line strings sharing a hash code.",
  "cases": [
    {
      "input": {
        "op": "serialize",
        "object": {
          "type": "LineString",
          "coordinates": [
            [
              4.889259338378906,
              52.370725881211314
            ],
            [
              4.895267486572266,
              52.3711451105601
            ],
            [
              4.892091751098633,
              52.36931095278263
            ],
            [
              4.889259338378906,
              52.370725881211314
            ]
          ]
        },
        "formatting": "none"
      },
      "expected_output": "{\"type\":\"LineString\",\"coordinates\":[[4.889259338378906,52.370725881211314],[4.895267486572266,52.3711451105601],[4.892091751098633,52.36931095278263],[4.889259338378906,52.370725881211314]]}\n"
    },
    {
      "input": {
        "op": "is_closed",
        "geometry": {
          "type": "LineString",
          "coordinates": [
            [
              4.889259338378906,
              52.370725881211314
            ],
            [
              4.895267486572266,
              52.3711451105601
            ],
            [
              4.892091751098633,
              52.36931095278263
            ],
            [
              4.889259338378906,
              52.370725881211314
            ]
          ]
        }
      },
      "expected_output": "is_closed=true\nis_linear_ring=true\n"
    },
    {
      "input": {
        "op": "construct",
        "object": {
          "type": "LineString",
          "coordinates": null
        }
      },
      "expected_output": "error=argument_null\nparam=coordinates\n"
    }
  ]
}

