Here are the public test cases for feature15_default_crs:
{
  "description": "When no CRS is supplied, a GeoJSON object omits the CRS member entirely on serialization, and an object read from text that has no CRS member carries no CRS. When a named CRS is present on a geometry, it is serialized after the coordinates as a nested named-system object and is restored on read. The well-known default geographic CRS is just a named system carrying its canonical name.",
  "cases": [
    {
      "input": {
        "op": "serialize",
        "object": {
          "kind": "feature_collection",
          "features": []
        },
        "formatting": "none"
      },
      "expected_output": "{\"type\":\"FeatureCollection\",\"features\":[]}\n"
    },
    {
      "input": {
        "op": "serialize",
        "object": {
          "type": "Point",
          "coordinates": [
            34.56,
            12.34
          ],
          "crs": {
            "kind": "named",
            "name": "TEST NAME"
          }
        },
        "formatting": "none"
      },
      "expected_output": "{\"type\":\"Point\",\"coordinates\":[34.56,12.34],\"crs\":{\"properties\":{\"name\":\"TEST NAME\"},\"type\":\"name\"}}\n"
    }
  ]
}

