Here are the public test cases for feature17_feature_deserialize:
{
  "description": "Reading a feature reconstructs its geometry, identifier, and properties from text and re-emits them in canonical form. A feature with properties keeps them; a feature without properties yields an empty property bag; a feature whose geometry member is null, or absent entirely, yields a feature with no geometry.",
  "cases": [
    {
      "input": {
        "op": "roundtrip",
        "target": "Feature",
        "wire": "{\"type\":\"Feature\",\"id\":\"test-id\",\"geometry\":{\"type\":\"Point\",\"coordinates\":[125.6,10.1]},\"properties\":{\"name\":\"Dinagat Islands\"}}"
      },
      "expected_output": "{\"type\":\"Feature\",\"id\":\"test-id\",\"geometry\":{\"type\":\"Point\",\"coordinates\":[125.6,10.1]},\"properties\":{\"name\":\"Dinagat Islands\"}}\n"
    }
  ]
}

